``` javascript
function reductions (coll, iteratee, seed) {
  var steps = [];
  var sum = coll.reduce((acc, val, i) => {
    steps.push(acc);
    var acc = iteratee(acc, val, i);
    return acc;
  }, seed);
  steps.push(sum);
  return steps;
}
```

